import myOpenGL     from '../../myOpenGL.js'

// Hàm đọc file JSON (có thể bỏ vào DialogueAPI hoặc js_glue.js)
const LoadIngredientsDB = async function(_f) {
  try {
    const response = await fetch(`${_f}?t=${Date.now()}`);
    const data = await response.json();
    return data;
  } catch (err) {
    console.error("❌ Lỗi nạp dữ liệu nguyên liệu:", err);
    return [];
  }
};

async function reload_shader(food_name) {
  if(!window.DialogueAPI._currentCanvas) return;
  const gl = window.DialogueAPI._currentCanvas;
  // const fragSrc = window._codeditor.getValue();

  try {
    // Fetch shader source
    const response = await fetch("./resources/mathNote/shader/frag_cook.glsl");
    if (!response.ok) {
      // Throwing an error here is identical to calling reject()
      throw new Error(`HTTP error! Shader fetch failed: ${response.status}`);
    }
    const fragSrc = await response.text();

    // Dynamic import image
    const imageModule = await import(`/resources/items/ingredients_${food_name}.png`);
    const actualImageElement = await window.App.loadImage(imageModule.default);
    gl.fLoadTexture("tex001", actualImageElement, true);

    // 1. DỌN RÁC (MEMORY MANAGEMENT)
    // Nếu Wrapper của bạn có hàm hủy thì gọi nó (VD: gl.gShader.destroy())
    // Nếu không, hãy gọi thẳng API của WebGL để xóa Program cũ:
    if (gl.gShader && gl.gShader.program) {
      gl.deleteProgram(gl.gShader.program); 
      console.log("🗑️ Đã xóa Shader cũ an toàn");
    }

    // 2. BIÊN DỊCH SHADER MỚI
    gl.gShader = new myOpenGL.ThuyShader(gl, gl.gCamera.projectionMatrix, fragSrc)
      .activate()
      .setTexture(gl.mTextureCache["tex001"], "uMainTex");
    console.log("✅ Cập nhật Shader thành công!");

  } catch (err) {
    // Bắt lỗi nếu người dùng gõ code GLSL sai (rất hay xảy ra khi live-coding)
    console.error("❌ Lỗi biên dịch Shader:", err);
  }
}

// Helper function to update shader
function updateShaderOffset(item) {
  if(!window.DialogueAPI._currentCanvas) return;
  const gl = window.DialogueAPI._currentCanvas;
  const x = item.col;
  const y = item.row; 
  gl.gShader.activate().setI('u_full', 0);
  gl.gShader.activate().setVec2('u_offset', x, y);
}

const postFunc = async(food_name, targetItem)=>{
  await window.App.init_gl();
  // 2. Initialize graphics
  try {
    console.log("Preparing kitchen...");
    await reload_shader(food_name);
    console.log("✅ Kitchen is ready!");
  } catch (err) {
    console.error("❌ Missing ingredients or graphics error!", err);
  }

  // Update shader to show the current ingredient (hoặc bạn có thể giấu nó đi nếu muốn)
  updateShaderOffset(targetItem);
};


export default async function(Module, entityId, C, API) {
  const e = window.App.entities[window.App.C.GetEntityName(entityId)];
  const speakerName = e.name;
  const food_name = speakerName;
  
  // 1. Load data
  const ingredients = await LoadIngredientsDB(`./resources/json/${food_name}.json`); 
  
  if (!e.npcProgress.isCompleted) {
    e.state = window.App.C.STATE_IDLE;
  }

  const choicesDiv             = document.getElementById('dialogue-choices');
  const dialogueDiv            = document.getElementById('dialogue-text');
  const css_origin             = choicesDiv.style.cssText;
  const css_origin_dialogueDiv = dialogueDiv.style.cssText;

  // Thiết lập Flexbox cho các nút lựa chọn để chúng dàn hàng ngang
  choicesDiv.style.cssText = "display: flex; flex-direction: row; justify-content: center; align-items: center; gap: 15px; flex-wrap: wrap; margin-top: 15px;";
  dialogueDiv.style.cssText = "max-height: 80%; overflow-y: auto;"; // Thêm overflow-y: auto để cuộn nếu lưới quá dài

  // ==========================================
  // STATE MACHINE VARIABLES
  // ==========================================
  let currentState = "TEACHING"; 
  let isInteracting = true;
  let needToPlayAudio = true; 

  while (isInteracting) {

    // --- WIN CONDITION ---
    if (e.npcProgress.solved >= e.npcProgress.total) {
      window.SpeakText("Hoàn thành xuất sắc!", 'vi-VN', 1.0, 1.2);
      await API.Say(entityId, speakerName, `### 👨‍🍳 Hoàn thành xuất sắc!\n\nChiếc ${food_name} đã được nấu xong. Cảm ơn đầu bếp nhí nhé!`);
      break; 
    }

    // ------------------------------------------------
    // STATE A: TEACHING (Show Recipe / Vocabulary)
    // ------------------------------------------------
    if (currentState === "TEACHING") {
      console.log("thuythuy");
      
      const SPRITE_SIZE = 128; 
      const TOTAL_COLUMNS = 4; // Số cột của file ảnh gốc
      const SHEET_WIDTH = SPRITE_SIZE * TOTAL_COLUMNS;

      // THIẾT LẬP LƯỚI 6 HÀNG X 4 CỘT
      // Bằng cách lặp lại 4 cột (1fr), và cho phép lưới mở rộng vô hạn hàng.
      // Nếu dữ liệu có 24 mục, nó sẽ tự động thành 6 hàng x 4 cột.
      let gridHTML = `<div style="display: grid; grid-template-columns: repeat(4, 1fr); gap: 10px; margin-top: 15px;">`;

      for (let i = 0; i < e.npcProgress.total; i++) {
        if (ingredients[i]) {
          const item = ingredients[i];
          
          const bgPosX = -(item.col * SPRITE_SIZE);
          const bgPosY = -(item.row * SPRITE_SIZE); 

          // Cú pháp inline siêu sạch để tránh lỗi Markdown
          const dynamicImgStyle = `width:${SPRITE_SIZE}px; height:${SPRITE_SIZE}px; background-image:url('./resources/items/ingredients_${food_name}.png'); background-position:${bgPosX}px ${bgPosY}px; background-size:${SHEET_WIDTH}px auto; background-repeat:no-repeat; margin-bottom:8px;`;

          gridHTML += `
<button class="recipe-item-btn" onclick="window.SpeakText('${item.en}', 'en-US', 0.85)">
<div class="recipe-item-img" style="${dynamicImgStyle}"></div>
<span class="recipe-item-en">${item.en}</span>
<span class="recipe-item-vi">(${item.vi})</span>
</button>`;
        }
      }
      
      gridHTML += `</div>`;

      const recipeText = `### 📖 Công thức món ${food_name}\n\nNhấn vào từng nguyên liệu để nghe cách đọc nhé!\n\n${gridHTML}`;
      
      const selectedIdx = await API.Ask(entityId, speakerName, recipeText, ["🍳 Bắt đầu nấu", "❌ Thoát"]);

      if (selectedIdx === 0) {
        currentState = "PRACTICE"; 
        needToPlayAudio = true; 
      } else {
        isInteracting = false; 
      }
    }

    // ------------------------------------------------
    // STATE B: PRACTICE (Cooking Minigame / Quiz)
    // ------------------------------------------------
    else if (currentState === "PRACTICE") {
      let currentScore = e.npcProgress.solved;
      const targetItem = ingredients[currentScore];

      const questionText = `
### 🍕 Cùng làm ${food_name} nào! (${currentScore}/${e.npcProgress.total})
Bé hãy chọn đúng hình của nguyên liệu **${targetItem.en}** (${targetItem.vi}) nhé!
`;

      const wrongPool = ingredients.filter(item => item.en !== targetItem.en).sort(() => Math.random() - 0.5);
      const choiceObjects = [
        { item: targetItem, isCorrect: true },
        { item: wrongPool[0], isCorrect: false },
        { item: wrongPool[1], isCorrect: false }
      ].sort(() => Math.random() - 0.5);

      // ==========================================
      // HÀM TẠO HÌNH ẢNH CHO NÚT BẤM (CSS SPRITES)
      // ==========================================

      const BTN_WIDTH  = 128;  // Đã sửa lại thành 128 (300 là quá lớn cho thiết bị di động/màn hình nhỏ)
      const BTN_HEIGHT = 128; 
      const TOTAL_COLUMNS = 4; // Số cột trên file ảnh gốc của bạn. Phải khớp chính xác!
      const SHEET_WIDTH = BTN_WIDTH * TOTAL_COLUMNS;

      function makeImageButton(item) {
        const bgPosX = -(item.col * BTN_WIDTH);
        const bgPosY = -(item.row * BTN_HEIGHT);
        
        // Trả về một thẻ div với kích thước chuẩn 125x128
        return `
<div style="width: ${BTN_WIDTH}px;
height: ${BTN_HEIGHT}px;
background-image: url('./resources/items/ingredients_${food_name}.png');
background-position: ${bgPosX}px ${bgPosY}px;
background-size: ${SHEET_WIDTH}px auto;
background-repeat: no-repeat;
margin: auto;">
</div>`;
      }

      const uiChoices = []; 
      
      // Bơm HTML hình ảnh vào làm lựa chọn
      choiceObjects.forEach(c => {
          uiChoices.push(makeImageButton(c.item)); 
      }); 
      
      uiChoices.push("🔊 Nghe lại"); 
      uiChoices.push("🔙 Xem lại công thức");

      if (needToPlayAudio) {
        window.SpeakText(targetItem.en, 'en-US', 0.85);
        needToPlayAudio = false; 
      }

      const selectedIdx = await API.Ask(entityId, speakerName, questionText, uiChoices);

      if (selectedIdx === -1) {
        isInteracting = false;
        break;
      }

      if (selectedIdx === uiChoices.length - 1) {
        currentState = "TEACHING";
        continue;
      }

      if (selectedIdx === uiChoices.length - 2) {
        window.SpeakText(targetItem.en, 'en-US', 0.85);
        continue;
      }

      const actualChoice = choiceObjects[selectedIdx];

      if (actualChoice.isCorrect) {
        window.TriggerFeedback(true);
        window.UpdateQuestProgress(entityId, true); 
        window.SpeakText(targetItem.en, 'en-US', 0.85);
        
        needToPlayAudio = true; 
      } else {
        window.TriggerFeedback(false);
        window.SpeakText(targetItem.en, 'en-US', 0.85);
        
        await API.Say(entityId, speakerName, `### ❌ Chưa đúng rồi!\n\nĐó là hình của món **${actualChoice.item.en}**.\nBé nghe lại và chọn cho đúng nhé!`);
      }
    }
  }

  // Phục hồi lại CSS ban đầu khi thoát
  choicesDiv.style.cssText = css_origin;
  dialogueDiv.style.cssText = css_origin_dialogueDiv;

  return true; 
}
